PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE rates_cache (
    base_currency TEXT PRIMARY KEY,
    rates_json TEXT NOT NULL,
    updated_at INTEGER NOT NULL
);
CREATE TABLE users (
    id TEXT PRIMARY KEY,
    name TEXT,
    country TEXT,
    first_seen INTEGER NOT NULL
);
CREATE TABLE conversions (
    id TEXT PRIMARY KEY,
    user_id TEXT,
    from_currency TEXT NOT NULL,
    to_currency TEXT NOT NULL,
    amount REAL,
    timestamp INTEGER NOT NULL
);
CREATE TABLE currency_snapshots (id TEXT PRIMARY KEY, date TEXT UNIQUE, snapshot_json TEXT, source TEXT, timestamp INTEGER);
CREATE TABLE cleanup_logs (id TEXT PRIMARY KEY, timestamp INTEGER, rows_deleted INTEGER, status TEXT, details TEXT);
CREATE TABLE settings (key TEXT PRIMARY KEY, value TEXT);
CREATE TABLE health_logs (id INTEGER PRIMARY KEY AUTOINCREMENT, status TEXT NOT NULL, details TEXT, response_time_ms INTEGER, timestamp DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE api_logs (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    endpoint TEXT NOT NULL,
    status TEXT NOT NULL,
    timestamp DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE social_traffic (id TEXT PRIMARY KEY, platform TEXT NOT NULL, country TEXT, device_type TEXT, status TEXT NOT NULL DEFAULT 'success', timestamp INTEGER NOT NULL);
CREATE TABLE healing_logs (id TEXT PRIMARY KEY, action TEXT NOT NULL, platform TEXT, status TEXT NOT NULL, details TEXT, timestamp INTEGER NOT NULL);
CREATE TABLE api_usage (
    month TEXT PRIMARY KEY, -- YYYY-MM
    fixer_calls INTEGER DEFAULT 0
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_conversions_timestamp ON conversions(timestamp);
CREATE INDEX idx_users_first_seen ON users(first_seen);
CREATE INDEX idx_rates_updated_at ON rates_cache(updated_at);
CREATE INDEX idx_snapshots_timestamp ON currency_snapshots(timestamp);
CREATE INDEX idx_users_country ON users(country);
CREATE INDEX idx_snapshots_date ON currency_snapshots(date);
CREATE INDEX idx_cleanup_timestamp ON cleanup_logs(timestamp);
CREATE INDEX idx_api_logs_timestamp ON api_logs(timestamp);
CREATE INDEX idx_social_traffic_platform ON social_traffic(platform);
CREATE INDEX idx_social_traffic_timestamp ON social_traffic(timestamp);
CREATE INDEX idx_social_traffic_status ON social_traffic(status);
CREATE INDEX idx_healing_logs_timestamp ON healing_logs(timestamp);
